```class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        if (num1 < 0) return -1;
        int res = 0;
        while (num1 > 0) {
            int i = min(num1, 60);
            num1 -= 2 * i + num2;
            res += i;
        }
        return num1 == 0 ? res : -1;
    }
};```
